 22→/**
 23→ * TM002 員工年度假別額度維護服務
 24→ * <p>
 25→ * 提供執行預設、明細查詢、儲存、刪除、批次驗證、批次匯入等功能。
 26→ *
 27→ * @author SoeTek Team
 28→ * @since 2026-03-26
 29→ */
 30→@Slf4j
 31→@ApplicationScoped
 32→public class Tm002EmpVacationService {
 33→
 34→    @Inject
 35→    @PersistenceUnit("eap")
 36→    EntityManager em;
 37→
 38→    /**
 39→     * 執行預設 — 查詢病假設定資料
 40→     * 業務規則 B3：僅回傳病假 1 筆（有效且日期在範圍內）
 41→     */
 42→    public List<Map<String, Object>> getDefaultVacation() {
 43→        String sql = """
 44→                SELECT A.VACATION_CODE, A.VACATION_NAME,
 45→                       B.VACATION_SUB_CODE, B.VACATION_SUB_NAME,
 46→                       B.VACATION_SUB_ID,
 47→                       B.MIN_HOURS, B.MAX_HOURS
 48→                  FROM EAP.TM_VACATION_SETTING A
 49→                  JOIN EAP.TM_VACATION_DETAIL_SETTING B
 50→                    ON A.VACATION_CODE = B.VACATION_CODE
 51→                 WHERE A.VACATION_NAME = NCHAR(30149) + NCHAR(20551)
 52→                   AND GETDATE() BETWEEN B.BEGIN_DATE
 53→                       AND ISNULL(B.END_DATE, CAST('2099-12-31' AS DATE))
 54→                   AND B.IS_EFFECTIVE = 1
 55→                """;
 56→
 57→        // 病 = U+75C5 = 30149, 假 = U+5047 = 20551
 58→        // Use NCHAR() to avoid encoding issues with Chinese characters
 59→        Query query = em.createNativeQuery(sql);
 60→        @SuppressWarnings("unchecked")
 61→        List<Object[]> rows = query.getResultList();
 62→
 63→        List<Map<String, Object>> result = new ArrayList<>();
 64→        for (Object[] row : rows) {
 65→            Map<String, Object> record = new HashMap<>();
 66→            record.put("vacationCode", row[0]);
 67→            record.put("vacationName", row[1]);
 68→            record.put("vacationSubCode", row[2]);
 69→            record.put("vacationSubName", row[3]);
 70→            record.put("vacationSubId", row[4]);
 71→            record.put("minHours", row[5]);
 72→            record.put("maxHours", row[6]);
 73→            result.add(record);
 74→        }
 75→        return result;
 76→    }
 77→
 78→    /**
 79→     * 查詢員工假別明細
 80→     */
 81→    public List<Map<String, Object>> queryEmpVacationDetail(Integer empId, int year) {
 82→        String sql = """
 83→                SELECT
 84→                    v.EMP_VACATION_ID,
 85→                    v.EMP_ID,
 86→                    v.VACATION_SUB_ID,
 87→                    vds.VACATION_CODE,
 88→                    vs.VACATION_NAME,
 89→                    vds.VACATION_SUB_CODE,
 90→                    vds.VACATION_SUB_NAME,
 91→                    v.MAX_HOURS,
 92→                    v.USED_HOURS,
 93→                    v.UNUSED_HOURS,
 94→                    v.CASH_OUT_HOURS,
 95→                    v.BEGIN_DATE,
 96→                    v.END_DATE,
 97→                    v.CLEAR
 98→                FROM EAP.TM_EMP_VACATION v
 99→                INNER JOIN EAP.TM_VACATION_DETAIL_SETTING vds
100→                    ON vds.VACATION_SUB_ID = v.VACATION_SUB_ID
101→                INNER JOIN EAP.TM_VACATION_SETTING vs
102→                    ON vs.VACATION_CODE = vds.VACATION_CODE
103→                WHERE v.EMP_ID = :empId
104→                  AND YEAR(v.BEGIN_DATE) = :year
105→                ORDER BY v.VACATION_SUB_ID
106→                """;
107→
108→        Query query = em.createNativeQuery(sql);
109→        query.setParameter("empId", empId);
110→        query.setParameter("year", year);
111→
112→        @SuppressWarnings("unchecked")
113→        List<Object[]> rows = query.getResultList();
114→
115→        List<Map<String, Object>> result = new ArrayList<>();
116→        for (Object[] row : rows) {
117→            Map<String, Object> record = new HashMap<>();
118→            record.put("empVacationId", row[0]);
119→            record.put("empId", row[1]);
120→            record.put("vacationSubId", row[2]);
121→            record.put("vacationCode", row[3]);
122→            record.put("vacationName", row[4]);
123→            record.put("vacationSubCode", row[5]);
124→            record.put("vacationSubName", row[6]);
125→
126→            BigDecimal maxHours = toBigDecimal(row[7]);
127→            BigDecimal usedHours = toBigDecimal(row[8]);
128→            BigDecimal unusedHours = toBigDecimal(row[9]);
129→
130→            record.put("maxHours", maxHours);
131→            record.put("totalHours", maxHours);
132→            record.put("usedHours", usedHours);
133→            record.put("unusedHours", unusedHours);
134→            record.put("remainingHours", unusedHours);
135→            record.put("cashOutHours", row[10]);
136→            record.put("beginDate", formatDate(row[11]));
137→            record.put("endDate", formatDate(row[12]));
138→
139→            // CLEAR 欄位 — 結算狀態
140→            Object clearVal = row[13];
141→            boolean isClear = false;
142→            if (clearVal != null) {
143→                if (clearVal instanceof Boolean) {
144→                    isClear = (Boolean) clearVal;
145→                } else if (clearVal instanceof Number) {
146→                    isClear = ((Number) clearVal).intValue() == 1;
147→                }
148→            }
149→            record.put("clear", isClear);
150→            record.put("settlementStatus", isClear ? "Y" : "");
151→
152→            result.add(record);
153→        }
154→        return result;
155→    }
156→
157→    /**
158→     * 儲存員工假別明細（新增 + 修改）
159→     * 業務規則 B1：UNUSED_HOURS = MAX_HOURS - USED_HOURS
160→     * 業務規則 B5：不修改 CLEAR 欄位
161→     */
162→    @Transactional
163→    @SuppressWarnings("unchecked")
164→    public List<Map<String, Object>> saveEmpVacationDetails(Integer empId, List<Map<String, Object>> details) {
165→        // 驗證員工存在
166→        String checkSql = "SELECT COUNT(*) FROM EAP.PM_EMPLOYEE WHERE EMP_ID = :empId";
167→        Query checkQuery = em.createNativeQuery(checkSql);
168→        checkQuery.setParameter("empId", empId);
169→        Number count = (Number) checkQuery.getSingleResult();
170→        if (count.intValue() == 0) {
171→            throw new BusinessException("EMP_NOT_FOUND", 400, "員工不存在：" + empId);
172→        }
173→
174→        List<Map<String, Object>> savedRecords = new ArrayList<>();
175→
176→        for (Map<String, Object> detail : details) {
177→            Object empVacationIdObj = detail.get("empVacationId");
178→            Integer vacationSubId = ((Number) detail.get("vacationSubId")).intValue();
179→            BigDecimal maxHours = toBigDecimal(detail.get("maxHours"));
180→            BigDecimal usedHours = toBigDecimal(detail.get("usedHours"));
181→            if (usedHours == null) usedHours = BigDecimal.ZERO;
182→
183→            // B1: 自動計算 UNUSED_HOURS
184→            BigDecimal unusedHours = maxHours.subtract(usedHours);
185→
186→            String beginDateStr = detail.get("beginDate").toString();
187→            String endDateStr = detail.get("endDate").toString();
188→            LocalDate beginDate = LocalDate.parse(beginDateStr);
189→            LocalDate endDate = LocalDate.parse(endDateStr);
190→
191→            TmEmpVacationEntity entity;
192→
193→            if (empVacationIdObj != null) {
194→                // 修改模式
195→                Integer empVacationId = ((Number) empVacationIdObj).intValue();
196→                entity = TmEmpVacationEntity.findByKey(empVacationId);
197→                if (entity == null) {
198→                    throw new BusinessException("RECORD_NOT_FOUND", 400, "記錄不存在：" + empVacationId);
199→                }
200→                // B5: 不修改 CLEAR 欄位 — 保留原值
201→                entity.vacationSubId = vacationSubId;
202→                entity.maxHours = maxHours;
203→                entity.usedHours = usedHours;
204→                entity.unusedHours = unusedHours;
205→                entity.beginDate = beginDate;
206→                entity.endDate = endDate;
207→            } else {
208→                // 新增模式
209→                entity = new TmEmpVacationEntity();
210→                entity.empId = empId;
211→                entity.vacationSubId = vacationSubId;
212→                entity.maxHours = maxHours;
213→                entity.usedHours = usedHours;
214→                entity.unusedHours = unusedHours;
215→                entity.cashOutHours = BigDecimal.ZERO;
216→                entity.beginDate = beginDate;
217→                entity.endDate = endDate;
218→                entity.clear = false;
219→                entity.persist();
220→            }
221→
222→            Map<String, Object> saved = new HashMap<>();
223→            saved.put("empVacationId", entity.empVacationId);
224→            saved.put("empId", entity.empId);
225→            saved.put("vacationSubId", entity.vacationSubId);
226→            saved.put("maxHours", entity.maxHours);
227→            saved.put("usedHours", entity.usedHours);
228→            saved.put("unusedHours", entity.unusedHours);
229→            saved.put("beginDate", DateFormatUtil.formatDate(entity.beginDate));
230→            saved.put("endDate", DateFormatUtil.formatDate(entity.endDate));
231→            savedRecords.add(saved);
232→        }
233→
234→        em.flush();
235→        return savedRecords;
236→    }
237→
238→    /**
239→     * 刪除員工假別明細（硬刪除）
240→     * 業務規則 B4：結算列（CLEAR=1）不可刪除
241→     * 業務規則 B6：非結算列硬刪除（DELETE FROM）
242→     */
243→    @Transactional
244→    public void deleteEmpVacation(Integer empVacationId) {
245→        TmEmpVacationEntity entity = TmEmpVacationEntity.findByKey(empVacationId);
246→        if (entity == null) {
247→            throw new BusinessException("RECORD_NOT_FOUND", 400, "記錄不存在：" + empVacationId);
248→        }
249→
250→        // B4: 結算列不可刪除
251→        if (Boolean.TRUE.equals(entity.clear)) {
252→            throw new BusinessException("CLEAR_CANNOT_DELETE", 400, "結算記錄不可刪除");
253→        }
254→
255→        // B6: 硬刪除
256→        entity.delete();
257→        em.flush();
258→    }
259→
260→    /**
261→     * 批次驗證員工
262→     * 業務規則 B10：
263→     * - 在職 → 有效
264→     * - 已離職 → 「員工已離職」
265→     * - 查不到 → 「查無此員工」
266→     */
267→    public List<Map<String, Object>> validateEmployees(List<String> empAccounts) {
268→        List<Map<String, Object>> results = new ArrayList<>();
269→
270→        for (String empAccount : empAccounts) {
271→            Map<String, Object> result = new HashMap<>();
272→            result.put("empAccount", empAccount);
273→
274→            String sql = """
275→                    SELECT e.EMP_ID, e.EMP_NAME, e.ORG_ID, e.LEAVE_DATE,
276→                           org.ORG_NAME
277→                    FROM EAP.PM_EMPLOYEE e
278→                    LEFT JOIN EAP.AU_ORGANIZATION org ON org.ORG_ID = e.ORG_ID
279→                    WHERE e.EMP_ACCOUNT = :empAccount
280→                    """;
281→            Query query = em.createNativeQuery(sql);
282→            query.setParameter("empAccount", empAccount);
283→
284→            @SuppressWarnings("unchecked")
285→            List<Object[]> rows = query.getResultList();
286→
287→            if (rows.isEmpty()) {
288→                result.put("valid", false);
289→                result.put("errorMessage", "查無此員工");
290→            } else {
291→                Object[] row = rows.get(0);
292→                Object leaveDate = row[3];
293→                boolean isResigned = leaveDate != null;
294→
295→                if (isResigned) {
296→                    result.put("valid", false);
297→                    result.put("errorMessage", "員工已離職");
298→                } else {
299→                    result.put("valid", true);
300→                    result.put("empId", row[0]);
301→                    result.put("empName", row[1]);
302→                    result.put("orgId", row[2]);
303→                    result.put("orgName", row[4]);
304→                }
305→            }
306→
307→            results.add(result);
308→        }
309→
310→        return results;
311→    }
312→
313→    /**
314→     * 批次匯入建立
315→     * 業務規則 B1：UNUSED_HOURS = MAX_HOURS - 0（新建已用為 0）
316→     * 業務規則 B11：結束日不可早於起始日
317→     */
318→    @Transactional
319→    @SuppressWarnings("unchecked")
320→    public int batchImport(Map<String, Object> payload) {
321→        // 驗證必填
322→        Object empIdsObj = payload.get("empIds");
323→        Object vacSubIdObj = payload.get("vacationSubId");
324→        Object maxHoursObj = payload.get("maxHours");
325→        Object beginDateObj = payload.get("beginDate");
326→        Object endDateObj = payload.get("endDate");
327→
328→        if (empIdsObj == null || !(empIdsObj instanceof List) || ((List<?>) empIdsObj).isEmpty()) {
329→            throw new BusinessException("REQUIRED_FIELD", 400, "empIds 為必填欄位");
330→        }
331→        if (vacSubIdObj == null) {
332→            throw new BusinessException("REQUIRED_FIELD", 400, "vacationSubId 為必填欄位");
333→        }
334→        if (maxHoursObj == null) {
335→            throw new BusinessException("REQUIRED_FIELD", 400, "maxHours 為必填欄位");
336→        }
337→        if (beginDateObj == null) {
338→            throw new BusinessException("REQUIRED_FIELD", 400, "beginDate 為必填欄位");
339→        }
340→        if (endDateObj == null) {
341→            throw new BusinessException("REQUIRED_FIELD", 400, "endDate 為必填欄位");
342→        }
343→
344→        List<Number> empIds = (List<Number>) empIdsObj;
345→        Integer vacationSubId = ((Number) vacSubIdObj).intValue();
346→        BigDecimal maxHours = toBigDecimal(maxHoursObj);
347→        LocalDate beginDate = LocalDate.parse(beginDateObj.toString());
348→        LocalDate endDate = LocalDate.parse(endDateObj.toString());
349→
350→        // B11: 結束日不可早於起始日
351→        if (endDate.isBefore(beginDate)) {
352→            throw new BusinessException("DATE_INVALID", 400, "結束日不可早於起始日");
353→        }
354→
355→        // 驗證假別細項存在
356→        String checkSql = "SELECT COUNT(*) FROM EAP.TM_VACATION_DETAIL_SETTING WHERE VACATION_SUB_ID = :vacSubId";
357→        Query checkQuery = em.createNativeQuery(checkSql);
358→        checkQuery.setParameter("vacSubId", vacationSubId);
359→        Number checkCount = (Number) checkQuery.getSingleResult();
360→        if (checkCount.intValue() == 0) {
361→            throw new BusinessException("VAC_SUB_NOT_FOUND", 400, "假別細項不存在：" + vacationSubId);
362→        }
363→
364→        // B1: UNUSED = MAX - 0
365→        BigDecimal unusedHours = maxHours;
366→
367→        int createdCount = 0;
368→        for (Number empIdNum : empIds) {
369→            Integer empId = empIdNum.intValue();
370→
371→            TmEmpVacationEntity entity = new TmEmpVacationEntity();
372→            entity.empId = empId;
373→            entity.vacationSubId = vacationSubId;
374→            entity.maxHours = maxHours;
375→            entity.usedHours = BigDecimal.ZERO;
376→            entity.unusedHours = unusedHours;
377→            entity.cashOutHours = BigDecimal.ZERO;
378→            entity.beginDate = beginDate;
379→            entity.endDate = endDate;
380→            entity.clear = false;
381→            entity.persist();
382→            createdCount++;
383→        }
384→
385→        em.flush();
386→        return createdCount;
387→    }
388→
389→    // ==================== 私有輔助方法 ====================
390→
391→    private BigDecimal toBigDecimal(Object obj) {
392→        if (obj == null) return null;
393→        if (obj instanceof BigDecimal) return (BigDecimal) obj;
394→        if (obj instanceof Number) return BigDecimal.valueOf(((Number) obj).doubleValue());
395→        try {
396→            return new BigDecimal(obj.toString().trim());
397→        } catch (NumberFormatException e) {
398→            return null;
399→        }
400→    }
401→
402→    private String formatDate(Object dateObj) {
403→        if (dateObj == null) return null;
404→        if (dateObj instanceof java.sql.Date sqlDate) {
405→            return DateFormatUtil.formatDate(sqlDate.toLocalDate());
406→        }
407→        if (dateObj instanceof java.sql.Timestamp timestamp) {
408→            return DateFormatUtil.formatDate(timestamp.toLocalDateTime().toLocalDate());
409→        }
410→        if (dateObj instanceof LocalDateTime localDateTime) {
411→            return DateFormatUtil.formatDate(localDateTime.toLocalDate());
412→        }
413→        if (dateObj instanceof LocalDate localDate) {
414→            return DateFormatUtil.formatDate(localDate);
415→        }
416→        String str = dateObj.toString();
417→        if (str.length() >= 10) {
418→            return str.substring(0, 10);
419→        }
420→        return str;
421→    }
422→}
