14→/**
15→ * TM 模組員工資訊查詢服務
16→ * <p>
17→ * 提供依員工編號查詢員工基本資訊的功能，
18→ * 供 TmEmpInfoQueryProcessor 和 TmUserOrgQueryProcessor 使用。
19→ *
20→ * @author SoeTek Team
21→ * @since 2026-03-17
22→ */
23→@Slf4j
24→@ApplicationScoped
25→public class TmEmployeeQueryService {
26→
27→    @Inject
28→    @PersistenceUnit("eap")
29→    EntityManager em;
30→
31→    /**
32→     * 依員工編號查詢員工基本資訊
33→     *
34→     * @param empAccount 員工編號
35→     * @return 員工資訊 Map，查無回傳 null
36→     */
37→    public Map<String, Object> getEmployeeByAccount(String empAccount) {
38→        String sql = """
39→                SELECT
40→                    e.EMP_ID        AS empId,
41→                    e.EMP_ACCOUNT   AS empAccount,
42→                    e.EMP_NAME      AS empName,
43→                    e.EMP_NAME_EN   AS empNameEn,
44→                    e.GENDER        AS gender,
45→                    e.ORG_ID        AS orgId,
46→                    org.ORG_NAME    AS orgName,
47→                    e.LEAVE_DATE    AS leaveDate
48→                FROM EAP.PM_EMPLOYEE e
49→                LEFT JOIN EAP.AU_ORGANIZATION org ON org.ORG_ID = e.ORG_ID
50→                WHERE e.EMP_ACCOUNT = :empAccount
51→                """;
52→
53→        Query query = em.createNativeQuery(sql);
54→        query.setParameter("empAccount", empAccount);
55→
56→        @SuppressWarnings("unchecked")
57→        List<Object[]> rows = query.getResultList();
58→
59→        if (rows.isEmpty()) {
60→            return null;
61→        }
62→
63→        Object[] row = rows.get(0);
64→        Map<String, Object> result = new HashMap<>();
65→        result.put("empId", row[0]);
66→        result.put("empAccount", row[1]);
67→        result.put("empName", row[2]);
68→        result.put("empNameEn", row[3]);
69→        result.put("gender", row[4]);
70→        result.put("orgId", row[5]);
71→        result.put("orgName", row[6]);
72→        result.put("leaveDate", row[7]);
73→
74→        return result;
75→    }
76→
77→    /**
78→     * 依登入帳號查詢使用者組織資訊
79→     *
80→     * @param empAccount 登入帳號
81→     * @return 使用者組織資訊 Map，查無回傳 null
82→     */
83→    public Map<String, Object> getUserOrgInfo(String empAccount) {
84→        // 同 getEmployeeByAccount 但可擴充更多組織資訊
85→        return getEmployeeByAccount(empAccount);
86→    }
87→}
