21→/**
22→ * TM002 執行預設（病假載入）Processor
23→ * <p>
24→ * 執行預設 SQL，回傳病假設定資料（僅病假 1 筆）
25→ * API 路徑：POST /api/tm002DefaultVacation
26→ *
27→ * @author SoeTek Team
28→ * @since 2026-03-26
29→ */
30→@Slf4j
31→@ApplicationScoped
32→@Named("tm002DefaultVacationProcessor")
33→@RegisterForReflection
34→public class Tm002DefaultVacationProcessor extends ApiRouteProcessor {
35→
36→    @Inject
37→    Tm002EmpVacationService empVacationService;
38→
39→    @Override
40→    public Map<String, Object> getTemplateParams() {
41→        return Map.of(
42→                "routeId", "tm002DefaultVacation",
43→                "apiDescription", "執行預設（病假載入）",
44→                "requiredFields", "");
45→    }
46→
47→    @Override
48→    protected String getProcessorType() {
49→        return LogType.API_PROCESSING;
50→    }
51→
52→    @Override
53→    @ActivateRequestContext
54→    @AuditLog(
55→            operation = AuditLog.OperationType.QUERY,
56→            entity = "TmVacationDetailSetting",
57→            description = "執行預設（病假載入）",
58→            logParameters = true,
59→            logResult = true
